ALTER TABLE projects ADD COLUMN deletedAt TIMESTAMP NULL DEFAULT NULL, ADD COLUMN deletedBy INT NULL DEFAULT NULL;
ALTER TABLE media ADD COLUMN deletedAt TIMESTAMP NULL DEFAULT NULL, ADD COLUMN deletedBy INT NULL DEFAULT NULL;
ALTER TABLE flights ADD COLUMN deletedAt TIMESTAMP NULL DEFAULT NULL, ADD COLUMN deletedBy INT NULL DEFAULT NULL;
ALTER TABLE clients ADD COLUMN deletedAt TIMESTAMP NULL DEFAULT NULL, ADD COLUMN deletedBy INT NULL DEFAULT NULL;
CREATE TABLE IF NOT EXISTS audit_log (
  id INT AUTO_INCREMENT PRIMARY KEY,
  action VARCHAR(50) NOT NULL,
  entityType VARCHAR(50) NOT NULL,
  entityId INT NOT NULL,
  entityName VARCHAR(255),
  userId INT NOT NULL,
  userName VARCHAR(255),
  details TEXT,
  ipAddress VARCHAR(45),
  createdAt TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX idx_audit_log_entity ON audit_log(entityType, entityId);
CREATE INDEX idx_audit_log_user ON audit_log(userId);
CREATE INDEX idx_audit_log_created ON audit_log(createdAt);

